import axios from "axios";

const API="http://localhost:5000/api/auth";

export const signupUser = async(data)=>{

    return await axios.post(
        `${API}/signup`,
        data
    );

};

export const loginUser = async(data)=>{

    return await axios.post(
        `${API}/login`,
        data
    );

};
